const TIPOS = new Set(['parametros-componente','interfaces-compatibilidade','software-firmware','dados-geometricos','normas-regulamentacoes','desempenho-ensaio','conformidade-certificados','solucoes-mercado','fornecedores-integradores','casos-aplicacao','processos-procedimentos','literatura-tecnica','dados-layout-infraestrutura','dados-seguranca-funcionais','dados-conectividade-comunicacao','modelos-interoperabilidade']);
const CONTAINERS = new Set(['ficha-tecnica','tabela-comparativa','catalogo-solucoes','inventario-normas','repositorio-referencias','planilha-dados-brutos','mapa-fornecedores','dossier-interface','registro-ensaios','caderno-procedimentos','conformidade-regulatoria','dossie-tecnico-tdp','registro-conflitos','evidence-pack']);

const task = $input.item.json;
const rawTags = (task.tags || []).map(t => (t.name || t).toLowerCase().trim());

const tipo_dado = rawTags.find(t => TIPOS.has(t));
const container = rawTags.find(t => CONTAINERS.has(t));

if (!tipo_dado) throw new Error('Tag tipo_dado nao encontrada. Tags presentes: ' + rawTags.join(', '));
if (!container) throw new Error('Tag container nao encontrada. Tags presentes: ' + rawTags.join(', '));

return [{
  json: {
    task_id: task.id,
    task_name: (task.name || task.text_content || 'tarefa').slice(0, 80),
    task_description: task.description || task.text_content || task.markdown_description || '',
    tipo_dado,
    container,
    started_at: new Date().toISOString()
  }
}];

const BASE = 'https://raw.githubusercontent.com/Borbofruto/Automaturge/main';
const { tipo_dado, container } = $json;

const get = async (path) => {
  const r = await $helpers.httpRequest({ method: 'GET', url: BASE + path });
  return typeof r === 'string' ? r : JSON.stringify(r);
};

const [templateTipo, templateContainer, promptOrderer, promptExecutor, promptSupervisor] = await Promise.all([
  get('/standards/data-types/' + tipo_dado + '.md'),
  get('/standards/containers/' + container + '.md'),
  get('/prompts/orderer.md'),
  get('/prompts/executor.md'),
  get('/prompts/supervisor.md')
]);

// Extrai conteudo entre o primeiro bloco de codigo markdown (``` ... ```)
const extractPrompt = (md) => {
  const match = md.match(/^```[^\n]*\n([\s\S]*?)\n```/m);
  return match ? match[1].trim() : md.trim();
};

return [{
  json: {
    ...$json,
    template_tipo_dado: templateTipo,
    template_container: templateContainer,
    prompt_orderer: extractPrompt(promptOrderer),
    prompt_executor: extractPrompt(promptExecutor),
    prompt_supervisor: extractPrompt(promptSupervisor)
  }
}];

const prev = $('Montar Input Ordenador').item.json;
const resp = $input.item.json;

let parsed;
try {
  const content = resp.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('Ordenador nao retornou JSON valido: ' + e.message);
}

if (!parsed.execution_brief) throw new Error('execution_brief ausente na resposta do Ordenador');
if (!parsed.validation_brief) throw new Error('validation_brief ausente na resposta do Ordenador');

return [{
  json: {
    ...prev,
    execution_brief: parsed.execution_brief,
    validation_brief: parsed.validation_brief,
    tokens_ordenador: resp.usage?.total_tokens || 0
  }
}];

const { execution_brief } = $json;
const queries = execution_brief.search_queries || [];
const apiKey = $env.SERPER_API_KEY;

if (!apiKey || queries.length === 0) {
  return [{ json: { ...$json, search_results: [], search_formatted: '(sem resultados de busca — SERPER_API_KEY nao configurada ou sem queries)' } }];
}

const results = [];
for (const query of queries.slice(0, 8)) {
  try {
    const resp = await $helpers.httpRequest({
      method: 'POST',
      url: 'https://google.serper.dev/search',
      headers: { 'X-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: JSON.stringify({ q: query, num: 5 })
    });
    const data = typeof resp === 'string' ? JSON.parse(resp) : resp;
    results.push({
      query,
      results: (data.organic || []).slice(0, 5).map(r => ({ title: r.title, url: r.link, snippet: r.snippet }))
    });
  } catch(e) {
    results.push({ query, results: [], error: e.message });
  }
}

const formatted = results.map(r => {
  const items = r.error
    ? '  ERRO: ' + r.error
    : r.results.map((i, idx) => '  [' + (idx+1) + '] ' + i.title + '\n      URL: ' + i.url + '\n      ' + i.snippet).join('\n');
  return 'QUERY: "' + r.query + '"\n' + (items || '  Sem resultados');
}).join('\n\n');

return [{ json: { ...$json, search_results: results, search_formatted: formatted } }];

const prev = $('Executar Buscas').item.json;
const resp = $input.item.json;

let parsed;
try {
  const content = resp.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('Executor 1 nao retornou JSON valido: ' + e.message);
}

return [{
  json: {
    ...prev,
    executor_output: parsed,
    current_attempt: 1,
    tokens_executor: resp.usage?.total_tokens || 0
  }
}];

const prev = $('Parsear Executor 1').item.json;
const resp = $input.item.json;

let validation;
try {
  const content = resp.choices[0].message.content;
  validation = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('Supervisor 1 nao retornou JSON valido: ' + e.message);
}

return [{
  json: {
    ...prev,
    validation: validation,
    tokens_supervisor: resp.usage?.total_tokens || 0
  }
}];

const prev = $input.item.json;
const retryInstructions = prev.validation.retry_instructions || 'Revisar e melhorar o output anterior.';

const updatedBrief = {
  ...prev.execution_brief,
  specific_instructions: prev.execution_brief.specific_instructions +
    '\n\n--- RETRY (Tentativa 1 rejeitada pelo Supervisor) ---\n' +
    retryInstructions +
    '\n\nOutput da tentativa 1 para referencia:\n' +
    JSON.stringify(prev.executor_output, null, 2)
};

return [{
  json: {
    ...prev,
    execution_brief: updatedBrief,
    current_attempt: 2
  }
}];

const prev = $('Preparar Retry').item.json;
const resp = $input.item.json;

let parsed;
try {
  const content = resp.choices[0].message.content;
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('Executor 2 nao retornou JSON valido: ' + e.message);
}

return [{
  json: {
    ...prev,
    executor_output: parsed,
    current_attempt: 2
  }
}];

const prev = $('Parsear Executor 2').item.json;
const resp = $input.item.json;

let validation;
try {
  const content = resp.choices[0].message.content;
  validation = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('Supervisor 2 nao retornou JSON valido: ' + e.message);
}

return [{
  json: {
    ...prev,
    validation: validation
  }
}];

const output = $json.executor_output || {};
const content = output.content || '(sem conteudo)';
const filename = output.output_filename || ($json.task_name.replace(/[^a-zA-Z0-9_-]/g, '_') + '_' + new Date().toISOString().slice(0,10) + '.md');

// Monta documento completo com anexos
let fullDoc = content;

if (output.repositorio_referencias?.length) {
  fullDoc += '\n\n---\n\n## Repositorio de Referencias\n\n';
  fullDoc += output.repositorio_referencias.map(r =>
    '[' + r.id + '] **' + r.titulo + '**\n' +
    '- Tipo: ' + r.tipo + '\n' +
    '- URL: ' + r.url + '\n' +
    '- Acesso: ' + r.data_acesso + '\n' +
    '- Status: ' + r.status
  ).join('\n\n');
}

if (output.registro_conflitos?.length) {
  fullDoc += '\n\n---\n\n## Registro de Conflitos\n\n';
  fullDoc += output.registro_conflitos.map(c =>
    '**' + c.id + '** — ' + c.campo + '\n' +
    '- Valor A: ' + c.valor_a + '\n' +
    '- Valor B: ' + c.valor_b + '\n' +
    '- Tipo: ' + c.tipo
  ).join('\n\n');
}

if (output.null_missing?.length) {
  fullDoc += '\n\n---\n\n## Campos NULL-MISSING\n\n';
  fullDoc += output.null_missing.map(n => '- ' + n).join('\n');
}

// Relatorio do Supervisor
const v = $json.validation || {};
fullDoc += '\n\n---\n\n## Relatorio do Supervisor\n\n' +
  '- Score: ' + (v.content_score || 'N/A') + '\n' +
  '- Maturidade alvo: ' + (v.maturity_target || 'N/A') + '\n' +
  '- Maturidade atingida: ' + (v.maturity_achieved || 'N/A') + '\n' +
  '- Tentativa: ' + ($json.current_attempt || 1) + '\n\n' +
  (v.feedback_summary || '');

const buffer = Buffer.from(fullDoc, 'utf-8');

return [{
  json: { ...$json, upload_filename: filename },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: filename
    }
  }
}];
